MOD = 10000

def main():
    import sys
    data = sys.stdin.read().split()
    if not data:
        return

    N = int(data[0])
    K = int(data[1])

    fixed = [0] * N
    for i in range(K):
        day = int(data[2 + 2 * i]) - 1
        pasta = int(data[3 + 2 * i])
        fixed[day] = pasta

    # DP table: dp[i][a][b] = number of ways to have pasta a on day i-1 and pasta b on day i
    # We'll use a 2D DP that tracks (yesterday, today)
    dp = [[0] * 4 for _ in range(4)]  # indices 1-3 for pasta types

    # Initialize first two days
    if fixed[0] and fixed[1]:
        dp[fixed[0]][fixed[1]] = 1
    elif fixed[0] and not fixed[1]:
        for b in range(1, 4):
            if b != fixed[0] or True:  # First two days can be same
                dp[fixed[0]][b] = 1
    elif not fixed[0] and fixed[1]:
        for a in range(1, 4):
            if a != fixed[1] or True:  # First two days can be same
                dp[a][fixed[1]] = 1
    else:
        for a in range(1, 4):
            for b in range(1, 4):
                dp[a][b] = 1

    # Iterate from day 2 to day N-1 (0-indexed: from index 2 to N-1)
    for i in range(2, N):
        new_dp = [[0] * 4 for _ in range(4)]

        for a in range(1, 4):  # pasta at day i-2
            for b in range(1, 4):  # pasta at day i-1
                if dp[a][b] == 0:
                    continue

                # Possible choices for today (day i)
                choices = [1, 2, 3] if fixed[i] == 0 else [fixed[i]]

                for c in choices:
                    # Check if three consecutive same
                    if a == b == c:
                        continue

                    new_dp[b][c] = (new_dp[b][c] + dp[a][b]) % MOD

        dp = new_dp

    # Sum all valid sequences of length N
    total = 0
    for a in range(1, 4):
        for b in range(1, 4):
            total = (total + dp[a][b]) % MOD

    print(total)

