    # Compute factorials modulo MOD
    fact = 1
    for i in range(2, N + 1):
        fact = (fact * i) % MOD

    fact2 = 1
    for i in range(2, M + 1):
        fact2 = (fact2 * i) % MOD

    ans = (fact * fact2) % MOD

    if N == M:
        ans = (ans * 2) % MOD  # two possible starting species

    print(ans)

