def count_combinations(n, s, start=0):
    if n == 0:
        return 1 if s == 0 else 0
    if start > 9:
        return 0
    total = 0
    for digit in range(start, 10):
        if s < digit:
            break
        total += count_combinations(n-1, s-digit, digit+1)
    return total

