import sys

def solve(graph, start, goal, m):
    INF = 10**9
    dist = [INF] * m
    visited = [False] * m
    dist[start] = 0

    while True:
        min_dist = INF
        u = -1
        for i in range(m):
            if not visited[i] and dist[i] < min_dist:
                min_dist = dist[i]
                u = i

        if u == -1 or u == goal:
            break

        visited[u] = True

        for v in range(m):
            if not visited[v] and graph[u][v] != INF:
                new_dist = dist[u] + graph[u][v]
                if new_dist < dist[v]:
                    dist[v] = new_dist

    return dist[goal]

