import sys

def main():
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it)); M = int(next(it))
    section = [[] for _ in range(M+1)]
    for i in range(N):
        l = int(next(it)); r = int(next(it))
        length = r - l + 1
        if length <= M:
            section[length].append((l, r))
        # else: it is always covered by any d, so we count it in the initial K.

    # Fenwick tree
    class Fenw:
        def __init__(self, n):
            self.n = n
            self.tree = [0] * (n+1)
        def add(self, index, delta):
            i = index
            while i <= self.n:
                self.tree[i] += delta
                i += i & -i
        def sum(self, index):
            s = 0
            i = index
            while i:
                s += self.tree[i]
                i -= i & -i
            return s

    fenw = Fenw(M+2)
    K = N
    output_lines = []
    for d in range(1, M+1):
        for (l, r) in section[d]:
            fenw.add(l, 1)
            fenw.add(r+1, -1)
            K -= 1
        ans = K
        # Count the number of intervals of length <= d that cover a multiple of d.
        for s in range(1, M//d + 1):
            station = s * d
            if station > M:
                break
            ans += fenw.sum(station)
        output_lines.append(str(ans))

    sys.stdout.write("\n".join(output_lines))

