class SegTree(object):
    def __init__(self, op, e, n, init_val):
        self.num = 1 << (n - 1).bit_length()
        self.S = [e] * (self.num * 2)
        self.op = op
        self.e = e
        for i, v in enumerate(init_val):
            if i < n:
                self.S[self.num + i] = v
        for i in range(self.num - 1, 0, -1):
            self.S[i] = self.op(self.S[i * 2], self.S[i * 2 + 1])

    def set(self, index, value):
        idx = self.num + index
        self.S[idx] = value
        while idx > 1:
            idx >>= 1
            self.S[idx] = self.op(self.S[idx * 2], self.S[idx * 2 + 1])

    def prod(self, l, r):
        if l >= r:
            return self.e
        res_left = self.e
        res_right = self.e
        l += self.num
        r += self.num
        while l < r:
            if l & 1:
                res_left = self.op(res_left, self.S[l])
                l += 1
            if r & 1:
                r -= 1
                res_right = self.op(self.S[r], res_right)
            l >>= 1
            r >>= 1
        return self.op(res_left, res_right)

