input = sys.stdin.readline

def main():
    data = sys.stdin.read().split()
    if not data:
        return

    it = iter(data)
    n = int(next(it)); m = int(next(it)); L = int(next(it))
    inf = 10**18
    d = [[inf] * n for _ in range(n)]
    for i in range(n):
        d[i][i] = 0

    for _ in range(m):
        a = int(next(it)) - 1
        b = int(next(it)) - 1
        c = int(next(it))
        if c < d[a][b]:
            d[a][b] = c
            d[b][a] = c

    # First Floyd-Warshall: compute all-pairs shortest distances
    for k in range(n):
        for i in range(n):
            if d[i][k] == inf:
                continue
            for j in range(n):
                if d[i][k] + d[k][j] < d[i][j]:
                    d[i][j] = d[i][k] + d[k][j]

    # Create graph d2: number of refills needed for each edge (if distance <= L, then 1 refill? Actually, we set to 1 meaning we can traverse without refill in the middle?
    # Actually, we are going to create a graph where an edge exists if the original distance is <= L. Then the cost for that edge is 1 (meaning we use one tank of fuel without refill in between).
    # But note: we start with a full tank. So if we go from i to j without refill, we don't need to refill at j? Actually, we refill at the start? No.
    # The problem: we need the number of times to full the tank (excluding the initial full tank).
    # So we define a new graph where each edge has weight 1 if the original distance <= L (meaning we can go without refill in the middle), but actually we are going to compute the number of refills required.
    d2 = [[inf] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if d[i][j] <= L:
                d2[i][j] = 1
            else:
                d2[i][j] = inf
        d2[i][i] = 0

    # Second Floyd-Warshall: compute the minimum number of edges (refills) between nodes
    for k in range(n):
        for i in range(n):
            if d2[i][k] == inf:
                continue
            for j in range(n):
                if d2[i][k] + d2[k][j] < d2[i][j]:
                    d2[i][j] = d2[i][k] + d2[k][j]

    q = int(next(it))
    res = []
    for _ in range(q):
        s = int(next(it)) - 1
        t = int(next(it)) - 1
        if d2[s][t] == inf:
            res.append("-1")
        else:
            # Subtract 1 because we start with a full tank (so the number of refills is one less than the number of segments)
            res.append(str(d2[s][t] - 1))

    print("\n".join(res))

