def kosaraju(edges, reverse_edges):
    v_count = len(edges)
    order = [0] * v_count
    k = [1]  # mutable counter

    def get_order(v):
        order[v] = 1  # mark as visited
        for dest in edges[v]:
            if order[dest] == 0:
                get_order(dest)
        order[v] = k[0]
        k[0] += 1

    def get_components(v):
        order[v] = 0  # mark as visited in second phase
        comp = [v]
        for dest in reverse_edges[v]:
            if order[dest] > 0:  # not visited in this phase
                comp.extend(get_components(dest))
        return comp

    # First DFS: compute finishing order
    for v in range(v_count):
        if order[v] == 0:
            get_order(v)

    # Second DFS: collect components in reverse finishing order
    components = []
    for v, _ in sorted(enumerate(order), key=lambda x: x[1], reverse=True):
        if order[v] > 0:
            components.append(get_components(v))

    return components


