import sys
sys.setrecursionlimit(2147483647)

mod = 10**9 + 7

def modinv(a, mod):
    return pow(a, mod-2, mod)

def nCr(n, r):
    if r > n or r < 0:
        return 0
    if r == 0 or r == n:
        return 1
    numerator = 1
    denominator = 1
    for i in range(r):
        numerator = (numerator * (n - i)) % mod
        denominator = (denominator * (i + 1)) % mod
    return (numerator * modinv(denominator, mod)) % mod

def main():
    r1, c1, r2, c2 = map(int, sys.stdin.readline().split())

    # Precompute factorials for efficiency
    max_n = r2 + c2 + 2
    fact = [1] * (max_n + 1)
    for i in range(1, max_n + 1):
        fact[i] = (fact[i-1] * i) % mod

    def nCr_fact(n, r):
        if r > n or r < 0:
            return 0
        return (fact[n] * modinv(fact[n-r], mod) % mod) * modinv(fact[r], mod) % mod

    # Using the hockey stick identity:
    # Sum from i=r1 to r2, j=c1 to c2 of C(i+j, i)
    # This equals: C(r2+c2+1, r2+1) - C(r1-1+c2+1, r1-1+1) - C(r2+c1-1+1, r2+1) + C(r1-1+c1-1, r1-1+1)

    result = 0

    # Calculate C(r2+c2+1, r2+1)
    result = (result + nCr_fact(r2 + c2 + 1, r2 + 1)) % mod

    # Subtract C(r1-1+c2+1, r1-1+1) 
    if r1 > 0:
        result = (result - nCr_fact(r1 - 1 + c2 + 1, r1 - 1 + 1)) % mod

    # Subtract C(r2+c1-1+1, r2+1)
    if c1 > 0:
        result = (result - nCr_fact(r2 + c1 - 1 + 1, r2 + 1)) % mod

    # Add C(r1-1+c1-1, r1-1+1)
    if r1 > 0 and c1 > 0:
        result = (result + nCr_fact(r1 - 1 + c1 - 1, r1 - 1 + 1)) % mod

    print(result)

