def calc_combination(n, s, max_digit):
    # Base case: if we want only one number
    if n == 1:
        # If sum is within range and non-negative
        if 0 <= s <= max_digit:
            return 1
        else:
            return 0

    # Early termination checks
    if s < 0:
        return 0

    # Minimum possible sum with n different numbers from 0 to max_digit
    min_sum = n * (n - 1) // 2  # 0 + 1 + 2 + ... + (n-1)
    if s < min_sum:
        return 0

    # Maximum possible sum with n different numbers from 0 to max_digit  
    max_sum = n * max_digit - n * (n - 1) // 2  # max_digit + (max_digit-1) + ... + (max_digit-n+1)
    if s > max_sum:
        return 0

    # Try all valid first digits
    total = 0
    # First digit can be 0 to min(s, max_digit)
    for first in range(min(s, max_digit) + 1):
        # Remaining n-1 numbers must be chosen from values less than first 
        # such that they sum to (s - first)
        # So the maximum digit available for rest is (first - 1)
        if first > 0:
            total += calc_combination(n-1, s-first, first-1)

    return total

