def kosaraju(edges, reverse_edges):
    import sys
    sys.setrecursionlimit(10**7)
    v_count = len(edges)
    visited = [False] * v_count
    order = []

    def dfs1(v):
        visited[v] = True
        for dest in edges[v]:
            if not visited[dest]:
                dfs1(dest)
        order.append(v)

    # First DFS to get finishing order
    for i in range(v_count):
        if not visited[i]:
            dfs1(i)

    # Reset visited array
    visited = [False] * v_count

    def dfs2(v, component):
        visited[v] = True
        component.append(v)
        for dest in reverse_edges[v]:
            if not visited[dest]:
                dfs2(dest, component)

    # Second DFS to find strongly connected components
    scc_list = []
    while order:
        v = order.pop()
        if not visited[v]:
            component = []
            dfs2(v, component)
            scc_list.append(component)

    return scc_list

