import sys

alpha = ["","'.!?","abcABC","defDEF","ghiGHI","jklJKL","mnoMNO","pqrsPQRS","tuvTUV","wxyzWXYZ"]

def solve(s):
    result = ""
    consecutive = ""

    for char in s:
        if char == '0':
            if consecutive:
                # Process the previous consecutive presses
                button = int(consecutive[0])
                num_presses = len(consecutive)
                if button == 0:
                    # 0 pressed multiple times = spaces
                    result += ' ' * (num_presses - 1)
                else:
                    # Normal button - get appropriate character
                    chars = alpha[button]
                    char_index = (num_presses - 1) % len(chars)
                    result += chars[char_index]
                consecutive = ""
            else:
                # 0 by itself - multiple spaces
                result += ' '  # Only one space from single 0
        else:
            if consecutive and consecutive[0] == char:
                # Continue counting same button
                consecutive += char
            else:
                # Process previous if exists, start new
                if consecutive:
                    button = int(consecutive[0])
                    num_presses = len(consecutive)
                    if button != 0:
                        chars = alpha[button]
                        char_index = (num_presses - 1) % len(chars)
                        result += chars[char_index]
                consecutive = char

    # Process remaining consecutive presses
    if consecutive:
        button = int(consecutive[0])
        num_presses = len(consecutive)
        if button != 0:
            chars = alpha[button]
            char_index = (num_presses - 1) % len(chars)
            result += chars[char_index]

    return result 

