def nCkpow(n, k):
    # Handle edge cases
    if k > n or k < 0:
        return 0
    if k == 0 or k == n:
        return 1

    # Calculate C(n,k) = n! / (k! * (n-k)!)
    # But we do it efficiently to avoid large factorials
    result = 1
    for i in range(min(k, n - k)):
        result = result * (n - i) // (i + 1)

    # For each position, we have 9 choices (1-9) for non-zero digits
    # When we choose positions for non-zero digits, each such digit can be 1-9
    return result * (9 ** k)

def count_valid_numbers(s, pos, k, is_limit, is_started):
    # This is a digit DP solution
    if pos == len(s):
        return 1 if k == 0 and is_started else 0

    # Memoization
    if (pos, k, is_limit, is_started) in memo:
        return memo[(pos, k, is_limit, is_started)]

    # Determine the upper limit for current digit
    limit = int(s[pos]) if is_limit else 9
    result = 0

    # Try all possible digits at current position
    for digit in range(0, limit + 1):
        new_k = k
        new_is_started = is_started or (digit > 0)

        if digit > 0:
            # Non-zero digit
            if k > 0:  # Only count if we still need more non-zero digits
                new_k = k - 1
                result += count_valid_numbers(s, pos + 1, new_k, is_limit and (digit == limit), new_is_started)
        else:
            # Zero digit
            result += count_valid_numbers(s, pos + 1, k, is_limit and (digit == limit), new_is_started)

    memo[(pos, k, is_limit, is_started)] = result
    return result

def solve(N, K):
    # Special handling for empty string/zero case
    if len(N) == 1 and N == "0":
        return 0

    global memo
    memo = {}

    # We're counting numbers from 1 to N with exactly K non-zero digits
    # So we calculate count(1 to N) - count(1 to 0) = count(1 to N)
    return count_valid_numbers(N, 0, K, True, False)

# Alternative direct approach for smallish values
def count_with_exactly_k_nonzero_digits_up_to_n(n_str, k):
    # Using digit DP approach
    if not n_str:
        return 0

    memo = {}

    def dp(pos, remaining_nonzeros, is_tight, is_number_started):
        # If we've processed all digits
        if pos == len(n_str):
            return 1 if remaining_nonzeros == 0 and is_number_started else 0

        if (pos, remaining_nonzeros, is_tight, is_number_started) in memo:
            return memo[(pos, remaining_nonzeros, is_tight, is_number_started)]

        # Maximum digit we can place here
        max_digit = int(n_str[pos]) if is_tight else 9
        result = 0

        # Try placing each digit
        for digit in range(0, max_digit + 1):
            new_remaining = remaining_nonzeros
            new_is_tight = is_tight and (digit == max_digit)
            new_is_number_started = is_number_started or (digit > 0)

            if digit == 0:
                # Placing 0 - doesn't reduce count of non-zero digits
                result += dp(pos + 1, remaining_nonzeros, new_is_tight, new_is_number_started)
            else:
                # Placing 1-9 - reduces count of non-zero digits by 1
                if remaining_nonzeros > 0:
                    result += dp(pos + 1, remaining_nonzeros - 1, new_is_tight, new_is_number_started)

        memo[(pos, remaining_nonzeros, is_tight, is_number_started)] = result
        return result

    return dp(0, k, True, False)

