import heapq
import sys

def dijkstra(graph, start, goal, is_cost):
    # Priority queue: (distance, node)
    pq = [(0, start)]
    distances = [float('inf')] * len(graph)
    distances[start] = 0

    while pq:
        current_dist, current_node = heapq.heappop(pq)

        if current_dist > distances[current_node]:
            continue

        if current_node == goal:
            return distances[goal]

        for neighbor, weight in graph[current_node]:
            if is_cost:
                # For cost, we want minimum cost
                new_dist = distances[current_node] + weight[0]  # weight[0] is cost
            else:
                # For time, we want minimum time
                new_dist = distances[current_node] + weight[1]  # weight[1] is time

            if new_dist < distances[neighbor]:
                distances[neighbor] = new_dist
                heapq.heappush(pq, (new_dist, neighbor))

    return distances[goal]

def solve(graph, start, goal, is_cost):
    return dijkstra(graph, start, goal, is_cost)

